// MARK: - Codec

private class MessagesPigeonCodecReader: FlutterStandardReader {
  override func readValue(ofType type: UInt8) -> Any? {
    switch type {
    case 129:
      return ConfigMessage.fromList(self.readValue() as! [Any?])
    case 130:
      return ConsentMessage.fromList(self.readValue() as! [Any?])
    case 131:
      return AttributionMessage.fromList(self.readValue() as! [Any?])
    case 132:
      return DeepLinkMessage.fromList(self.readValue() as! [Any?])
    case 133:
      return NativeAdMediaMessage.fromList(self.readValue() as! [Any?])
    case 134:
      return NativeAdMessage.fromList(self.readValue() as! [Any?])
    case 135:
      return UpdateMessage.fromList(self.readValue() as! [Any?])
    case 136:
      return AppMessageMessage.fromList(self.readValue() as! [Any?])
    default:
      return super.readValue(ofType: type)
    }
  }
}

private class MessagesPigeonCodecWriter: FlutterStandardWriter {
  override func writeValue(_ value: Any) {
    if let value = value as? ConfigMessage {
      super.writeByte(129)
      super.writeValue(value.toList())
    } else if let value = value as? ConsentMessage {
      super.writeByte(130)
      super.writeValue(value.toList())
    } else if let value = value as? AttributionMessage {
      super.writeByte(131)
      super.writeValue(value.toList())
    } else if let value = value as? DeepLinkMessage {
      super.writeByte(132)
      super.writeValue(value.toList())
    } else if let value = value as? NativeAdMediaMessage {
      super.writeByte(133)
      super.writeValue(value.toList())
    } else if let value = value as? NativeAdMessage {
      super.writeByte(134)
      super.writeValue(value.toList())
    } else if let value = value as? UpdateMessage {
      super.writeByte(135)
      super.writeValue(value.toList())
    } else if let value = value as? AppMessageMessage {
      super.writeByte(136)
      super.writeValue(value.toList())
    } else {
      super.writeValue(value)
    }
  }
}

private class MessagesPigeonCodecReaderWriter: FlutterStandardReaderWriter {
  override func reader(with data: Data) -> FlutterStandardReader {
    return MessagesPigeonCodecReader(data: data)
  }

  override func writer(with data: NSMutableData) -> FlutterStandardWriter {
    return MessagesPigeonCodecWriter(data: data)
  }
}

class MessagesPigeonCodec: FlutterStandardMessageCodec, @unchecked Sendable {
  static let shared = MessagesPigeonCodec(readerWriter: MessagesPigeonCodecReaderWriter())
}

