      name: "dev.flutter.pigeon.mtracker.MtrackerHostApi.initialize\(channelSuffix)",
      binaryMessenger: binaryMessenger, codec: codec)
    if let api = api {
      initializeChannel.setMessageHandler { message, reply in
        let args = message as! [Any?]
        let configArg = args[0] as! ConfigMessage
        do {
          try api.initialize(config: configArg)
          reply(wrapResult(nil))
        } catch {
          reply(wrapError(error))
        }
      }
    } else {
      initializeChannel.setMessageHandler(nil)
    }

    let requestTrackingConsentChannel = FlutterBasicMessageChannel(
      name: "dev.flutter.pigeon.mtracker.MtrackerHostApi.requestTrackingConsent\(channelSuffix)",
      binaryMessenger: binaryMessenger, codec: codec)
    if let api = api {
      requestTrackingConsentChannel.setMessageHandler { _, reply in
        api.requestTrackingConsent { result in
          switch result {
          case .success(let res):
            reply(wrapResult(res))
          case .failure(let error):
            reply(wrapError(error))
