      }
    } else {
      setConsentChannel.setMessageHandler(nil)
    }

    let trackEventChannel = FlutterBasicMessageChannel(
      name: "dev.flutter.pigeon.mtracker.MtrackerHostApi.trackEvent\(channelSuffix)",
      binaryMessenger: binaryMessenger, codec: codec)
    if let api = api {
