    } else {
      trackEventChannel.setMessageHandler(nil)
    }

    let loadAdChannel = FlutterBasicMessageChannel(
      name: "dev.flutter.pigeon.mtracker.MtrackerHostApi.loadAd\(channelSuffix)",
      binaryMessenger: binaryMessenger, codec: codec)
    if let api = api {
      loadAdChannel.setMessageHandler { message, reply in
        let args = message as! [Any?]
        let slotIdArg = args[0] as! String
        api.loadAd(slotId: slotIdArg) { result in
          switch result {
          case .success(let res):
            reply(wrapResult(res))
          case .failure(let error):
            reply(wrapError(error))
          }
        }
      }
    } else {
      loadAdChannel.setMessageHandler(nil)
    }

    let getConfigJsonChannel = FlutterBasicMessageChannel(
      name: "dev.flutter.pigeon.mtracker.MtrackerHostApi.getConfigJson\(channelSuffix)",
      binaryMessenger: binaryMessenger, codec: codec)
    if let api = api {
      getConfigJsonChannel.setMessageHandler { message, reply in
        let args = message as! [Any?]
        let keyArg = args[0] as! String
        api.getConfigJson(key: keyArg) { result in
          switch result {
          case .success(let res):
            reply(wrapResult(res))
          case .failure(let error):
            reply(wrapError(error))
          }
        }
      }
    } else {
      getConfigJsonChannel.setMessageHandler(nil)
