  func onUpdateAvailable(data dataArg: UpdateMessage, completion: @escaping (Result<Void, PigeonError>) -> Void)
  func onMessage(data dataArg: AppMessageMessage, completion: @escaping (Result<Void, PigeonError>) -> Void)
}

class MtrackerFlutterApi: MtrackerFlutterApiProtocol {
  private let binaryMessenger: FlutterBinaryMessenger
  private let messageChannelSuffix: String

  init(binaryMessenger: FlutterBinaryMessenger, messageChannelSuffix: String = "") {
    self.binaryMessenger = binaryMessenger
    self.messageChannelSuffix = messageChannelSuffix.count > 0 ? ".\(messageChannelSuffix)" : ""
  }

  var codec: MessagesPigeonCodec { MessagesPigeonCodec.shared }

  func onAttribution(
    data dataArg: AttributionMessage,
    completion: @escaping (Result<Void, PigeonError>) -> Void
  ) {
    let channelName =
      "dev.flutter.pigeon.mtracker.MtrackerFlutterApi.onAttribution\(messageChannelSuffix)"
    let channel = FlutterBasicMessageChannel(
      name: channelName, binaryMessenger: binaryMessenger, codec: codec)
    channel.sendMessage([dataArg] as [Any?]) { _ in
      completion(.success(()))
    }
  }

  func onDeepLink(
    data dataArg: DeepLinkMessage,
    completion: @escaping (Result<Void, PigeonError>) -> Void
